6	//! Half-precision atomic histogram checks.
7	//!
8	//! Run: cargo oxide run atomic_f16
9	
10	#![feature(f16)]
11	
12	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
13	use cuda_device::atomic::{AtomicOrdering, BlockAtomicF16, DeviceAtomicF16, SystemAtomicF16};
14	use cuda_device::{DisjointSlice, kernel, thread};
15	use cuda_host::cuda_module;
16	
17	#[cuda_module]
18	mod kernels {
19	    use super::*;
20	
21	    #[kernel]
22	    pub fn device_hist_f16(hist: &[f16], mut old: DisjointSlice<f16>, n: u32, nbins: u32) {
23	        let gid = thread::index_1d();
24	        let i = gid.get();
25	        if i >= n as usize {
26	            return;
27	        }
28	
29	        let bin = i % nbins as usize;
30	        let cell = unsafe { &*(hist.as_ptr().add(bin) as *const DeviceAtomicF16) };
31	        let prev = cell.fetch_add(1.0f16, AtomicOrdering::Relaxed);
32	        if let Some(out_elem) = old.get_mut(gid) {
33	            *out_elem = prev;
34	        }
35	    }
36	
37	    #[kernel]
38	    pub fn block_hist_f16(hist: &[f16], mut old: DisjointSlice<f16>) {
39	        let gid = thread::index_1d();
40	        let block = thread::blockIdx_x() as usize;
41	        let cell = unsafe { &*(hist.as_ptr().add(block) as *const BlockAtomicF16) };
42	        let prev = cell.fetch_add(1.0f16, AtomicOrdering::Relaxed);
43	        if let Some(out_elem) = old.get_mut(gid) {
44	            *out_elem = prev;
45	        }
46	    }
47	
48	    #[kernel]
49	    pub fn device_sub_f16(counter: &[f16], mut old: DisjointSlice<f16>) {
50	        let gid = thread::index_1d();
51	        let cell = unsafe { &*(counter.as_ptr() as *const DeviceAtomicF16) };
52	        let prev = cell.fetch_sub(1.0f16, AtomicOrdering::Relaxed);
53	        if let Some(out_elem) = old.get_mut(gid) {
54	            *out_elem = prev;
55	        }
56	    }
57	
58	    #[kernel]
59	    pub fn system_add_f16(counter: &[f16], mut old: DisjointSlice<f16>) {
60	        let gid = thread::index_1d();
61	        let cell = unsafe { &*(counter.as_ptr() as *const SystemAtomicF16) };
62	        let prev = cell.fetch_add(1.0f16, AtomicOrdering::Relaxed);
63	        if let Some(out_elem) = old.get_mut(gid) {
64	            *out_elem = prev;
65	        }
66	    }
67	
68	    #[kernel]
69	    pub fn device_swap_f16(cell: &[f16], vals: &[f16], mut old: DisjointSlice<f16>, n: u32) {
70	        let gid = thread::index_1d();
71	        let i = gid.get();
72	        if i >= n as usize {
73	            return;
74	        }
75	        let cell = unsafe { &*(cell.as_ptr() as *const DeviceAtomicF16) };
76	        let prev = cell.swap(vals[i], AtomicOrdering::Relaxed);
77	        if let Some(out_elem) = old.get_mut(gid) {
78	            *out_elem = prev;
79	        }
80	    }
81	
82	    #[kernel]
83	    pub fn device_store_load_f16(cells: &[f16], mut out: DisjointSlice<f16>, n: u32) {
84	        let gid = thread::index_1d();
85	        let i = gid.get();
86	        if i >= n as usize {
87	            return;
88	        }
89	        let cell = unsafe { &*(cells.as_ptr().add(i) as *const DeviceAtomicF16) };
90	        let seen = cell.load(AtomicOrdering::Acquire);
91	        cell.store(seen + 1.0f16, AtomicOrdering::Release);
92	        if let Some(out_elem) = out.get_mut(gid) {
93	            *out_elem = seen;
94	        }
95	    }
96	}
97	
98	fn main() {
99	    println!("=== DeviceAtomicF16 / BlockAtomicF16 tests ===\n");
100	
101	    let ctx = CudaContext::new(0).expect("Failed to create CUDA context");
102	    let stream = ctx.default_stream();
103	    let module = kernels::load(&ctx).expect("Failed to load embedded CUDA module");
104	
105	    run_device_hist(&module, &stream, 31, 16);
106	    run_device_hist(&module, &stream, 4096, 16);
107	    run_device_sub(&module, &stream, 256);
108	    run_system_add(&module, &stream, 256);
109	    run_device_swap(&module, &stream, 256);
110	    run_device_store_load(&module, &stream, 256);
111	    run_block_hist(&module, &stream, 4, 64);
112	
113	    println!("\nSUCCESS: all f16 atomic checks passed");
114	}
115	
116	fn run_device_hist(
117	    module: &kernels::LoadedModule,
118	    stream: &cuda_core::CudaStream,
119	    n: u32,
120	    nbins: u32,
121	) {
122	    println!("--- DeviceAtomicF16 histogram: n={n}, bins={nbins} ---");
123	
124	    let hist = DeviceBuffer::<f16>::zeroed(stream, nbins as usize).unwrap();
125	    let mut old = DeviceBuffer::<f16>::zeroed(stream, n as usize).unwrap();
126	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
127	    unsafe {
128	        module.device_hist_f16(
129	            stream,
130	            LaunchConfig::for_num_elems(n),
131	            &hist,
132	            &mut old,
133	            n,
134	            nbins,
135	        )
136	    }
137	    .expect("Kernel launch failed");
138	
139	    stream.synchronize().unwrap();
140	
141	    let counts: Vec<u16> = hist
142	        .to_host_vec(stream)
143	        .unwrap()
144	        .iter()
145	        .map(|v| v.to_bits())
146	        .collect();
147	    let old_values = old.to_host_vec(stream).unwrap();
148	
149	    let expected_counts: Vec<u16> = (0..nbins)
150	        .map(|bin| expected_bin_count(n, nbins, bin).to_bits())
151	        .collect();
152	    check_slice("final bin counts", &counts, &expected_counts);
153	    check_device_old_values(&old_values, n, nbins);
154	}
155	
156	fn run_device_sub(module: &kernels::LoadedModule, stream: &cuda_core::CudaStream, n: u32) {
157	    println!("--- DeviceAtomicF16 fetch_sub: n={n} ---");
158	
159	    let initial = vec![n as f16];
160	    let counter = DeviceBuffer::from_host(stream, &initial).unwrap();
161	    let mut old = DeviceBuffer::<f16>::zeroed(stream, n as usize).unwrap();
162	
163	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
164	    unsafe { module.device_sub_f16(stream, LaunchConfig::for_num_elems(n), &counter, &mut old) }
165	        .expect("Kernel launch failed");
166	
167	    stream.synchronize().unwrap();
168	
169	    let final_count = counter.to_host_vec(stream).unwrap()[0].to_bits();
170	    check_slice("fetch_sub final count", &[final_count], &[0.0f16.to_bits()]);
171	    check_old_range(
172	        "fetch_sub old values",
173	        &old.to_host_vec(stream).unwrap(),
174	        1,
175	        n,
176	    );
177	}
178	
179	fn run_system_add(module: &kernels::LoadedModule, stream: &cuda_core::CudaStream, n: u32) {
180	    println!("--- SystemAtomicF16 fetch_add: n={n} ---");
181	
182	    let counter = DeviceBuffer::<f16>::zeroed(stream, 1).unwrap();
183	    let mut old = DeviceBuffer::<f16>::zeroed(stream, n as usize).unwrap();
184	
185	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
186	    unsafe { module.system_add_f16(stream, LaunchConfig::for_num_elems(n), &counter, &mut old) }
187	        .expect("Kernel launch failed");
188	
189	    stream.synchronize().unwrap();
190	
191	    let final_count = counter.to_host_vec(stream).unwrap()[0].to_bits();
192	    check_slice(
193	        "system fetch_add final count",
194	        &[final_count],
195	        &[(n as f16).to_bits()],
196	    );
197	    check_old_sequence(
198	        "system fetch_add old values",
199	        &old.to_host_vec(stream).unwrap(),
200	        n,
201	    );
202	}
203	
204	fn run_device_swap(module: &kernels::LoadedModule, stream: &cuda_core::CudaStream, n: u32) {
205	    println!("--- DeviceAtomicF16 swap: n={n} ---");
206	
207	    let cell = DeviceBuffer::<f16>::zeroed(stream, 1).unwrap();
208	    let host_vals: Vec<f16> = (1..=n).map(|v| v as f16).collect();
209	    let vals = DeviceBuffer::from_host(stream, &host_vals).unwrap();
210	    let mut old = DeviceBuffer::<f16>::zeroed(stream, n as usize).unwrap();
211	
212	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
213	    unsafe {
214	        module.device_swap_f16(
215	            stream,
216	            LaunchConfig::for_num_elems(n),
217	            &cell,
218	            &vals,
219	            &mut old,
220	            n,
221	        )
222	    }
223	    .expect("Kernel launch failed");
224	
225	    stream.synchronize().unwrap();
226	
227	    // Each swap returns whatever the previous swap (or the initial zero) left
228	    // in the cell, so {old values} + {final} must equal {initial} + {vals}.
229	    let mut got: Vec<u16> = old
230	        .to_host_vec(stream)
231	        .unwrap()
232	        .iter()
233	        .map(|v| v.to_bits())
234	        .collect();
235	    got.push(cell.to_host_vec(stream).unwrap()[0].to_bits());
236	    got.sort();
237	
238	    let mut expected: Vec<u16> = std::iter::once(0.0f16)
239	        .chain(host_vals.iter().copied())
240	        .map(|v| v.to_bits())
241	        .collect();
242	    expected.sort();
243	
244	    check_slice("swap old values + final", &got, &expected);
245	}
246	
247	fn run_device_store_load(module: &kernels::LoadedModule, stream: &cuda_core::CudaStream, n: u32) {
248	    println!("--- DeviceAtomicF16 load/store: n={n} ---");
249	
250	    let host_init: Vec<f16> = (0..n).map(|v| v as f16).collect();
251	    let cells = DeviceBuffer::from_host(stream, &host_init).unwrap();
252	    let mut out = DeviceBuffer::<f16>::zeroed(stream, n as usize).unwrap();
253	
254	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
255	    unsafe {
256	        module.device_store_load_f16(stream, LaunchConfig::for_num_elems(n), &cells, &mut out, n)
257	    }
258	    .expect("Kernel launch failed");
259	
260	    stream.synchronize().unwrap();
261	
262	    let loaded: Vec<u16> = out
263	        .to_host_vec(stream)
264	        .unwrap()
265	        .iter()
266	        .map(|v| v.to_bits())
267	        .collect();
268	    let expected_loaded: Vec<u16> = host_init.iter().map(|v| v.to_bits()).collect();
269	    check_slice("atomic load values", &loaded, &expected_loaded);
270	
271	    let stored: Vec<u16> = cells
272	        .to_host_vec(stream)
273	        .unwrap()
274	        .iter()
275	        .map(|v| v.to_bits())
276	        .collect();
277	    let expected_stored: Vec<u16> = host_init.iter().map(|v| (*v + 1.0f16).to_bits()).collect();
278	    check_slice("atomic store values", &stored, &expected_stored);
279	}
280	
281	fn run_block_hist(
282	    module: &kernels::LoadedModule,
283	    stream: &cuda_core::CudaStream,
284	    blocks: u32,
285	    threads_per_block: u32,
286	) {
287	    println!(
288	        "--- BlockAtomicF16 histogram: blocks={blocks}, threads/block={threads_per_block} ---"
289	    );
290	
291	    let hist = DeviceBuffer::<f16>::zeroed(stream, blocks as usize).unwrap();
292	    let mut old =
293	        DeviceBuffer::<f16>::zeroed(stream, (blocks * threads_per_block) as usize).unwrap();
294	    let cfg = LaunchConfig {
295	        grid_dim: (blocks, 1, 1),
296	        block_dim: (threads_per_block, 1, 1),
297	        shared_mem_bytes: 0,
298	    };
299	
300	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
301	    unsafe { module.block_hist_f16(stream, cfg, &hist, &mut old) }.expect("Kernel launch failed");
302	
303	    stream.synchronize().unwrap();
304	
305	    let counts: Vec<u16> = hist
306	        .to_host_vec(stream)
307	        .unwrap()
308	        .iter()
309	        .map(|v| v.to_bits())
310	        .collect();
311	    let old_values = old.to_host_vec(stream).unwrap();
312	    let expected_counts = vec![(threads_per_block as f16).to_bits(); blocks as usize];
313	
314	    check_slice("block final counts", &counts, &expected_counts);
315	    for block in 0..blocks as usize {
316	        let start = block * threads_per_block as usize;
317	        let end = start + threads_per_block as usize;
318	        check_old_sequence(
319	            "block old values",
320	            &old_values[start..end],
321	            threads_per_block,
322	        );
323	    }
324	}
325	
326	fn expected_bin_count(n: u32, nbins: u32, bin: u32) -> f16 {
327	    let base = n / nbins;
328	    let remainder = n % nbins;
329	    (base + u32::from(bin < remainder)) as f16
330	}
331	
332	fn check_device_old_values(old_values: &[f16], n: u32, nbins: u32) {
333	    for bin in 0..nbins {
334	        let got: Vec<f16> = old_values
335	            .iter()
336	            .enumerate()
337	            .filter(|(i, _)| *i % nbins as usize == bin as usize)
338	            .map(|(_, &value)| value)
339	            .collect();
340	        check_old_sequence(
341	            "device old values",
342	            &got,
343	            expected_bin_count(n, nbins, bin) as u32,
344	        );
345	    }
346	}
347	
348	fn check_old_sequence(name: &str, got: &[f16], len: u32) {
349	    check_old_range(name, got, 0, len - 1);
350	}
351	
352	fn check_old_range(name: &str, got: &[f16], start: u32, end: u32) {
353	    let mut got_bits: Vec<u16> = got.iter().map(|value| value.to_bits()).collect();
354	    got_bits.sort();
355	
356	    let expected: Vec<u16> = (start..=end)
357	        .map(|value| (value as f16).to_bits())
358	        .collect();
359	    check_slice(name, &got_bits, &expected);
360	}
361	
362	fn check_slice<T: Eq + std::fmt::Debug>(name: &str, got: &[T], expected: &[T]) {
363	    if got == expected {
364	        println!("  PASS {name}: {got:?}");
365	    } else {
366	        eprintln!("  FAIL {name}: got {got:?}, expected {expected:?}");
367	        std::process::exit(1);
368	    }
369	}
