453	    /// - min should be 0 (thread 0's value)
454	    /// - max should be 255 (thread 255's value)
455	    ///
456	    /// This specifically tests the UMin/UMax path (unsigned), whereas test 13
457	    /// tests the Min/Max path (signed).
458	    #[kernel]
459	    pub fn atomic_unsigned_minmax_test(
460	        min_acc: &[u32],
461	        max_acc: &[u32],
462	        mut out: DisjointSlice<u32>,
463	    ) {
464	        let tid = thread::threadIdx_x();
465	        let gid = thread::index_1d();
466	
467	        let atomic_min = unsafe { &*(min_acc.as_ptr() as *const DeviceAtomicU32) };
468	        let atomic_max = unsafe { &*(max_acc.as_ptr() as *const DeviceAtomicU32) };
469	
470	        atomic_min.fetch_min(tid, AtomicOrdering::Relaxed);
471	        atomic_max.fetch_max(tid, AtomicOrdering::Relaxed);
472	
473	        if let Some(out_elem) = out.get_mut(gid) {
474	            *out_elem = tid;
475	        }
476	    }
