478	    /// Test 18: BlockAtomicU32 fetch_add -- block-scope (.cta) atomics.
479	    ///
480	    /// Uses BlockAtomicU32 which emits syncscope("block") → `.cta` in PTX.
481	    /// Since we launch a single block, block scope is correct here.
482	    /// The counter should reach N just like device-scope, but with cheaper
483	    /// coherence (block scope only guarantees visibility within the CTA).
484	    #[kernel]
485	    pub fn atomic_block_scope_test(counter: &[u32], mut out: DisjointSlice<u32>) {
486	        let gid = thread::index_1d();
487	
488	        let atomic_counter = unsafe { &*(counter.as_ptr() as *const BlockAtomicU32) };
489	
490	        let old = atomic_counter.fetch_add(1, AtomicOrdering::Relaxed);
491	
492	        if let Some(out_elem) = out.get_mut(gid) {
493	            *out_elem = old;
494	        }
495	    }
