503	    pub fn atomic_block_scope_acqrel_test(counter: &[u32], mut out: DisjointSlice<u32>) {
504	        let gid = thread::index_1d();
505	
506	        let atomic_counter = unsafe { &*(counter.as_ptr() as *const BlockAtomicU32) };
507	
508	        let old = atomic_counter.fetch_add(1, AtomicOrdering::AcqRel);
509	
510	        if let Some(out_elem) = out.get_mut(gid) {
511	            *out_elem = old;
512	        }
513	    }
